function logOut = fLogFilterV01(logDat,scanN,fltPrm,scanP)%% filter out logfile%% logOut = fLogFilterV01(logDat,scanN,fltPrm,scanP)%% logDat: log data% scanN: scan number to be taken, can be like [1:4,8]% fltPrm: N x 3 array, [filter parameter, min, max] for each filter% scanP: columns to be output, scan and shot are default%% logOut: output log data%%% Function Log Filter, ver.1% Kei Nakamura% Created on Saturday, November 27th 2010.% Modified on %%% filtering scannmbScn = numel(scanN);  % number of scansfor ii = 1:nmbScn        subDat = logDat(logDat(:,2)==scanN(ii),:);    if ii==1;        subDatOut = subDat;    else        subDatOut = [subDatOut;subDat]; % combining    endendclear subDat;logDat = subDatOut;clear subDatOut;%% filtering[nmbFlt,dlt] = size(fltPrm);    % number of filtersdisp('filter,min,max')for ii = 1:nmbFlt    minP = min(logDat(:,fltPrm(ii,1)));    maxP = max(logDat(:,fltPrm(ii,1)));    disp([ii,minP,maxP])    logDat = logDat(logDat(:,fltPrm(ii,1))>=fltPrm(ii,2),:);    logDat = logDat(logDat(:,fltPrm(ii,1))<=fltPrm(ii,3),:);end%% take only scan, shot number and scan parameter% disp(['std-B: ',num2str(std(logDat(:,24)))]);   % show std of magnetic filedlogOut = logDat(:,[2,3,24,scanP,5]);
